    badge: "Partner",
    name: _unref(displayName),
    initials: _unref(initials),
    subtitle: "Markup, client payment, and production dispatch",
    "breadcrumb-root": "Dashboard",
    "nav-items": _unref(navItems),
    "support-title": "Partner detail",
